const { ethers } = require('ethers');

// Decode the registerTourist call data from the logs
const data = '';

const interface = new ethers.Interface([
  "function registerTourist(string username, string email, string phone, uint256 dateOfBirth) external returns (string)"
]);

try {
  const decoded = interface.decodeFunctionData('registerTourist', data);
  console.log('Decoded registerTourist call:');
  console.log('  username:', decoded.username);
  console.log('  email:', decoded.email);
  console.log('  phone:', decoded.phone);
  console.log('  dateOfBirth:', decoded.dateOfBirth.toString());
} catch (e) {
  console.error('Failed to decode:', e.message);
}
